# Generated by ollama (llama3.1)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'ARTIFACT_URL', description: 'Artifact URL')
        string(name: 'SERVER_IP', description: 'Server IP')
        string(name: 'SERVER_USERNAME', description: 'Server username')
        string(name: 'SERVER_PASSWORD', description: 'Server password')
    }

    stages {
        stage('Download Artifact') {
            steps {
                sh "curl -O ${params.ARTIFACT_URL}"
            }
        }
        stage('Deploy to Production Server') {
            steps {
                withCredentials([usernamePassword(credentialsId: 'server-credentials', usernameVariable: 'SERVER_USERNAME', passwordVariable: 'SERVER_PASSWORD')]) {
                    sshagent(credsId: 'server-credentials') {
                        sh "scp -o StrictHostKeyChecking=no ${params.ARTIFACT_URL} ${params.SERVER_IP}:${params.SERVICE_NAME}"
                    }
                }
            }
        }
    }
}